1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: QuoteStep[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	const COMPONENT_PREMIUM = 25;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_PREMIUM = 60;
27	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
28	
29	const FIRST_INSURANCE_SURCHARGE = 1.1;
30	const CURSE_SURCHARGE_RATE = 0.5;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const LOYALTY_THRESHOLD_YEARS = 2;
34	const LOYALTY_DISCOUNT_RATE = 0.2;
35	const FOLLOWUP_DISCOUNT_RATE = 0.15;
36	const PROCESSING_FEE = 5;
37	
38	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
39	
40	const sum = (values: number[]): number => values.reduce((acc, value) => acc + value, 0);
41	
42	// Base premium of a single item (main item or one component).
43	const itemBase = (item: Item): number =>
44	  isComponent(item) ? COMPONENT_PREMIUM : (BASE_PREMIUM[item.type] ?? 0);
45	
46	// A surcharge adds `rate` of the base premium for each affected item.
47	const surchargeFor = (items: Item[], affects: (item: Item) => boolean, rate: number): number =>
48	  sum(items.filter(affects).map((item) => rate * itemBase(item)));
49	
50	// Curse adds 50% of the affected item's base premium.
51	const curseSurcharge = (items: Item[]): number =>
52	  surchargeFor(items, (item) => item.cursed === true, CURSE_SURCHARGE_RATE);
53	
54	// High enchantment (level >= 5) adds 30% of the affected item's base premium.
55	const enchantmentSurcharge = (items: Item[]): number =>
56	  surchargeFor(
57	    items,
58	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
59	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
60	  );
61	
62	// Base premium for `count` alike components: a group of exactly 3 forms a
63	// block at COMPONENT_BLOCK_PREMIUM; otherwise each component costs
64	// COMPONENT_PREMIUM.
65	const componentGroupPremium = (count: number): number =>
66	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
67	
68	// Count how many alike components of each type appear (e.g. { rune: 2 }).
69	const countByType = (items: Item[]): Map<string, number> =>
70	  items.reduce((counts, item) => {
71	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
72	    return counts;
73	  }, new Map<string, number>());
74	
75	const mainItemsPremium = (items: Item[]): number =>
76	  sum(items.filter((item) => !isComponent(item)).map(itemBase));
77	
78	const componentsPremium = (items: Item[]): number =>
79	  sum([...countByType(items.filter(isComponent)).values()].map(componentGroupPremium));
80	
81	const basePremium = (items: Item[]): number =>
82	  mainItemsPremium(items) + componentsPremium(items);
83	
84	// Round up to a whole number in MHPCO's favour, guarding against
85	// floating-point noise (e.g. 197.5000000001) before the ceiling by snapping
86	// to 6 decimal places first.
87	const FLOAT_GUARD_PRECISION = 1e6;
88	const roundUpToWhole = (value: number): number =>
89	  Math.ceil(Math.round(value * FLOAT_GUARD_PRECISION) / FLOAT_GUARD_PRECISION);
90	
91	// Long-standing customers (>= 2 years) receive 20% off the policy base.
92	const loyaltyDiscount = (base: number, yearsWithMHPCO: number): number =>
93	  yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE * base : 0;
94	
95	// Every quote after the customer's first receives 15% off the policy base.
96	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
97	  isFollowUp ? FOLLOWUP_DISCOUNT_RATE * base : 0;
98	
99	// Premium for one quote: base premium plus the first-insurance surcharge,
100	// item-specific curse/enchantment surcharges, less the policy-wide loyalty
101	// and follow-up discounts, and the flat processing fee.
102	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowUp: boolean): number => {
103	  const base = basePremium(items);
104	  return (
105	    base * FIRST_INSURANCE_SURCHARGE +
106	    curseSurcharge(items) +
107	    enchantmentSurcharge(items) -
108	    loyaltyDiscount(base, yearsWithMHPCO) -
109	    followUpDiscount(base, isFollowUp) +
110	    PROCESSING_FEE
111	  );
112	};
113	
114	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
115	  const { yearsWithMHPCO } = scenario.customer;
116	  let quotesSeen = 0;
117	  const results = scenario.steps.map((step) => {
118	    const isFollowUp = quotesSeen > 0;
119	    quotesSeen += 1;
120	    return { premium: roundUpToWhole(quotePremium(step.items, yearsWithMHPCO, isFollowUp)) };
121	  });
122	  return { results };
123	};
